create table dirkspzm32.lvs_prod_linie_waren (
    sid                      varchar2(2 char) default '01' not null enable,
    firma_nr                 number(9, 0) default 1 not null enable,
    linie_nr                 number(*, 5) not null enable,
    waren_nr                 number(*, 5) not null enable,
    artikel_id               number(*, 0) not null enable,
    mhd                      date,
    produktionsdatum         date,
    charge                   varchar2(40 char) not null enable,
    auftragsnr               number(*, 5),
    labor_status             varchar2(1 char) not null enable,
    menge                    number(*, 3) not null enable,
    lieferant_nr             varchar2(20 char),
    best_nr                  number(*, 5),
    best_pos                 number(*, 5),
    li_nr_lief               varchar2(20 char),
    lte_id_lieferant         varchar2(20 char),
    sonst_id_lieferant       varchar2(20 char),
    leitzahl                 number(*, 5),
    fa_pos                   number(*, 5),
    fa_upos                  number(*, 5),
    menge_je_karton          number(*, 3),
    lam_p1                   varchar2(15 char),
    lam_p2                   varchar2(15 char),
    lam_p3                   varchar2(15 char),
    lam_p4                   varchar2(15 char),
    lam_p5                   varchar2(15 char),
    lam_p6                   varchar2(15 char),
    lam_p7                   varchar2(15 char),
    lam_p8                   varchar2(15 char),
    lam_p9                   varchar2(15 char),
    lam_p10                  varchar2(15 char),
    anzahl_lhm               number(*, 0),
    kunden_nr                varchar2(20 char),
    kd_art_nr                varchar2(30 char),
    zeichnung                varchar2(255 char),
    zeichnung_index          varchar2(10 char),
    labor_text               varchar2(30 char),
    lhm_name                 varchar2(50 char),
    lhm_eti_druck_status     varchar2(10 char) default 'SD',
    lam_text                 varchar2(40 char),
    qs_status                varchar2(10 char),
    owner_address_id         number(*, 0),
    lam_sel1                 varchar2(30 char),
    lam_sel2                 varchar2(30 char),
    lam_sel3                 varchar2(30 char),
    lam_sel4                 varchar2(30 char),
    lam_sel5                 varchar2(30 char),
    lam_sel6                 varchar2(30 char),
    lam_sel7                 varchar2(30 char),
    lam_sel8                 varchar2(30 char),
    lam_sel9                 varchar2(30 char),
    lam_sel10                varchar2(30 char),
    hersteller_kuerzel_liste varchar2(100 char),
    lte_id                   varchar2(20 char),
    lhm_id                   varchar2(20 char),
    charge_suffix            varchar2(20 char)
);

alter table dirkspzm32.lvs_prod_linie_waren
    add constraint pk_lvs_prod_linie_waren primary key ( linie_nr,
                                                         waren_nr )
        using index enable;


